// Static insight texts. Placeholders: {{stocks}}, {{top_holding}}, {{sector}}, {{holding_count}}, {{gain}}, {{cash_pct}}

export function renderInsight(template: string, data: Record<string, string>): string {
  return template.replace(/\{\{(\w+)\}\}/g, (_, key) => data[key] ?? key);
}

